 ** Source 모드 로직에서 초기화되지않는 체크포인트 데이터를 업데이트 하는 케이스가 존재하여 발생하였습니다.\xa0
 ** CLASSIC 모드에서만 발생
 * 수정
 ** Source 모드에서 체크포인트 데이터를\xa0 초기화해주고 레코드마다 업데이트해주도록 수정했습니다.

 * 체크포인트 잘못 업데이트 하는 케이스 상세 설명
 ** 특정 트랜잭션의 TX_START가 해당 Workset에 없고 TX_END인 레코드를 만나서 Source 모드에서 적용 성공한 상황에서 체크포인트가 잘못 업데이트 됩니다. 이후 다음 트랜잭션의 TX_END를 처리하기전에 모듈 종료된 경우 위 이슈 발생합니다.

 * 기타 (재현경로)

{noformat}
-- source --
create table TEST11
(
    I1 NUMBER not null,
    I2 NUMBER not null,
    I3 VARCHAR2(100),
    I4 VARCHAR2(100),
    I5 VARCHAR2(100),
    I6 DATE,
    I7 TIMESTAMP(6),
    primary key (I1, I2)
)

BEGIN
    FOR I IN 1..4 LOOP
        UPDATE SMOH.TEST11 SET I4 = 'ABCDE123F 123' WHERE I1 = I AND I2 = I;
    END LOOP;
    COMMIT;
    FOR I IN 5..5 LOOP
        UPDATE SMOH.TEST11 SET I4 = ' ABCDE123F 123' WHERE I1 = I AND I2 = I;
    END LOOP;
    COMMIT;
END;

-- target --

BEGIN
    FOR I IN 1..4 LOOP
        INSERT INTO SMOH.TEST11 VALUES (I, I, '가나다라 마바사', 'wow', '123',
                                             SYSDATE, SYSTIMESTAMP);
        IF MOD(I, 1000) = 0 THEN
            COMMIT;
        END IF;
    END LOOP;
    COMMIT;
END;

-- config --
PARALLELISM="no";
APPLIER_COUNT="";
BATCH_MODE="";
BATCH_PER_QUEUE="";
BYTES_PER_QUEUE="";
RECS_PER_BATCH="";
RECS_PER_QUEUE="";
GROUP_TRANSACTION="1";
SPLIT_TRANSACTION_RECORD_COUNT="1";
WORKSET_RECS_COUNT="0";

